def _normalize_protocols(protocol_text: str) -> list[str]:
    result: list[str] = []
    for item in protocol_text.split(","):
        protocol = item.strip()
        if protocol and protocol not in result:
            result.append(protocol)
    return result


def _extract_interface_info(content: str, class_name: str) -> tuple[list[str], list[str], int, int] | tuple[None, None, None, None]:
    implementation_anchor = f"@implementation {class_name}"
    implementation_index = content.find(implementation_anchor)
    if implementation_index < 0:
        return None, None, None, None

    pre_impl = content[:implementation_index]
    interface_matches = list(
        re.finditer(rf"@interface\s+{re.escape(class_name)}\s*\(\)\s*(?:<([^>]*)>)?", pre_impl)
    )
    if not interface_matches:
        return None, None, None, None

    start_match = interface_matches[0]
    interface_start = start_match.start()
    macro_start = pre_impl.rfind("#if ENABLE_ADS", max(0, interface_start - 240), interface_start)
    if macro_start >= 0:
        interface_start = macro_start

    interface_end = pre_impl.rfind("@end")
    if interface_end < 0 or interface_end < start_match.end():
        return None, None, None, None
    interface_end += len("@end")

    protocols: list[str] = []
    for match in interface_matches:
        protocol_text = match.group(1) or ""
        for protocol in _normalize_protocols(protocol_text):
            if protocol == "BUNativeExpressBannerViewDelegate":
                continue
            if protocol not in protocols:
                protocols.append(protocol)

    interface_body = pre_impl[start_match.end():interface_end - len("@end")]
    property_lines: list[str] = []
    for line in interface_body.splitlines():
        stripped = line.strip()
        if not stripped:
            property_lines.append("")
            continue
        if stripped.startswith("#if ") or stripped == "#else" or stripped == "#endif":
            continue
        if stripped.startswith("@interface ") or stripped == "@end":
            continue
        if stripped.startswith("#import "):
            continue
        if "BUNativeExpressBannerView *bannerAdView" in stripped:
            continue
        if "CGFloat bannerAdHeight" in stripped:
            continue
        if "Ad Logic" in stripped:
            continue
        property_lines.append(line.rstrip())

    while property_lines and not property_lines[0].strip():
        property_lines.pop(0)
    while property_lines and not property_lines[-1].strip():
        property_lines.pop()

    return protocols, property_lines, interface_start, interface_end


def _build_interface_block(class_name: str, protocols: list[str], property_lines: list[str]) -> str:
    protocol_text = ", ".join(protocols)
    ad_protocols = list(protocols)
    if "BUNativeExpressBannerViewDelegate" not in ad_protocols:
        ad_protocols.append("BUNativeExpressBannerViewDelegate")
    ad_protocol_text = ", ".join(ad_protocols)

    lines = [
        "#if ENABLE_ADS",
        "",
        '#import <BUAdSDK/BUAdSDK.h>',
        '#import "AdManager.h"',
        "",
        f"@interface {class_name} () <{ad_protocol_text}>",
        "",
        "@property(strong, nonatomic) BUNativeExpressBannerView *bannerAdView;",
        "@property(assign, nonatomic) CGFloat bannerAdHeight;",
        "",
        "#else",
        "",
        f"@interface {class_name} ()" + (f" <{protocol_text}>" if protocol_text else ""),
        "",
        "#endif",
        "",
    ]
    if property_lines:
        lines.extend(property_lines)
        lines.append("")
    lines.append("@end")
    return "\n".join(lines)


def _replace_interface_block(content: str, class_name: str) -> tuple[str, bool]:
    protocols, property_lines, start, end = _extract_interface_info(content, class_name)
    if protocols is None or property_lines is None or start is None or end is None:
