    [self.focusTime setControlsEnabled:NO];
    [self.restTime setControlsEnabled:NO];
    [self startTimerWithSeconds:self.focusMinutes * 60 phase:FocusPhaseFocusing];
}

- (void)startTimerWithSeconds:(NSInteger)seconds phase:(FocusPhase)phase {
    self.phase = phase;
    self.remainingSeconds = seconds;
    [self.timer invalidate];
    self.timer = [NSTimer scheduledTimerWithTimeInterval:1.0 target:self selector:@selector(timerTick) userInfo:nil repeats:YES];
    [[NSRunLoop mainRunLoop] addTimer:self.timer forMode:NSRunLoopCommonModes];
    [self updateCountdownLabelWithSeconds:self.remainingSeconds];
}

- (void)timerTick {
    if (self.remainingSeconds <= 0) {
        [self.timer invalidate];
        self.timer = nil;
        if (self.phase == FocusPhaseFocusing) {
            self.statusLabel.text = @"休息中";
            [self.actionButton setTitle:@"休息中" forState:UIControlStateNormal];
            [self startTimerWithSeconds:self.restMinutes * 60 phase:FocusPhaseResting];
        } else if (self.phase == FocusPhaseResting) {
            self.statusLabel.text = @"准备开始";
            self.isRunning = NO;
            [self.actionButton setTitle:@"开始" forState:UIControlStateNormal];
            [self.focusTime setControlsEnabled:YES];
            [self.restTime setControlsEnabled:YES];

            // 重置倒计时标签为当前专注时间
            [self updateCountdownLabelWithSeconds:self.focusMinutes * 60];

            if (self.focusMinutes >= 25) {
                if ([FocusManager sharedManager].focusCoins < 70) {
                    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"恭喜完成🎉" message:@"恭喜完成1次专注，专注币+5！" preferredStyle:UIAlertControllerStyleAlert];
                    UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil];
                    [alert addAction:okAction];
                    [self presentViewController:alert animated:YES completion:nil];

                    [[FocusManager sharedManager] addCoins:MIN(5, 70 - [FocusManager sharedManager].focusCoins)];
                } else {
                    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"专注币已满" message:@"您已达到70个专注币上限，专注币可用于解锁首页音频，快去使用吧！" preferredStyle:UIAlertControllerStyleAlert];
                    UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"知道了" style:UIAlertActionStyleDefault handler:nil];
                    [alert addAction:okAction];
                    [self presentViewController:alert animated:YES completion:nil];
                }
            } else {
                UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"专注完成✅" message:[NSString stringWithFormat:@"您已完成%ld分钟专注！专注时间需大于等于25分钟才能获得专注币，下次试试更长时间吧~", (long)self.focusMinutes] preferredStyle:UIAlertControllerStyleAlert];
                UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil];
                [alert addAction:okAction];
                [self presentViewController:alert animated:YES completion:nil];
            }
            [self updateCoinsUI];
        }
        return;
    }
    self.remainingSeconds -= 1;
    [self updateCountdownLabelWithSeconds:self.remainingSeconds];
}

- (void)updateCountdownLabelWithSeconds:(NSInteger)seconds {
    NSInteger m = seconds / 60;
    NSInteger s = seconds % 60;
    self.countDownLabel.text = [NSString stringWithFormat:@"%02ld:%02ld", (long)m, (long)s];
}

